def clean_places() -> list[dict]:
    """Normalize tuples → dicts. Some name_ar entries carry curation notes
    after '؟ لا —'; keep only the final (correct) part."""
    result = []
    for name_ar, name_en, category, region, lat, lng, rating, tags, description in PLACES:
        if "؟ لا —" in name_ar:
            name_ar = name_ar.split("؟ لا —")[-1].strip()
        if name_ar.endswith("؟"):
            name_ar = name_ar.rstrip("؟").strip()
        result.append(
            {
                "name_ar": name_ar,
                "name_en": name_en,
                "category": category,
                "region": region,
                "lat": round(lat, 3),
                "lng": round(lng, 3),
                "coords_verified": False,
                "rating": rating,
                "rating_count": max(12, int(rating * 40)),
                "tags": tags,
                "description": description,
                "approved": True,
                "images": [],
            }
        )
    return result
